@@ -533,7 +533,7 @@ impl HttpRetryConfig {
             .with_base_backoff_ms(self.initial_delay_ms)
             .with_max_backoff_ms(self.max_delay_ms)
             .with_jitter_enabled(self.jitter_enabled)
